"use client"

import { useState, useEffect, useRef } from "react"
import { useRouter } from "next/navigation"
import { cn } from "@/lib/utils"
import { ConditionGuide, type ConditionCode } from "@/components/seller/ConditionGuide"
import { ListingSuccessScreen } from "@/components/seller/ListingSuccessScreen"
import {
  createSellerListing,
  saveListingDraft,
  uploadListingImage,
  type CreateListingResult,
} from "@/lib/data/seller-dashboard"

interface CardListingFormProps {
  prefillSku?: string
}

interface GameOption {
  code: string
  name: string
}

interface SetOption {
  code: string
  name: string
}

type ShippingMethod = "standard" | "priority" | "free_over_25"

const SHIPPING_OPTIONS: Array<{
  value: ShippingMethod
  label: string
  price: string
  description: string
}> = [
  { value: "standard", label: "Standard Shipping", price: "$3.99", description: "5-7 business days" },
  { value: "priority", label: "Priority Shipping", price: "$7.99", description: "2-3 business days" },
  { value: "free_over_25", label: "Free Shipping", price: "Free", description: "Orders over $25 (5-7 business days)" },
]

const LANGUAGES = [
  { value: "EN", label: "English" },
  { value: "JP", label: "Japanese" },
  { value: "FR", label: "French" },
  { value: "DE", label: "German" },
  { value: "ES", label: "Spanish" },
  { value: "IT", label: "Italian" },
  { value: "PT", label: "Portuguese" },
  { value: "KO", label: "Korean" },
  { value: "CN", label: "Chinese" },
]

export function CardListingForm({ prefillSku }: CardListingFormProps) {
  const router = useRouter()
  const fileInputRef = useRef<HTMLInputElement>(null)

  const [cardName, setCardName] = useState("")
  const [gameCode, setGameCode] = useState("")
  const [setCode, setSetCode] = useState("")
  const [collectorNumber, setCollectorNumber] = useState("")
  const [condition, setCondition] = useState<ConditionCode>("NM")
  const [language, setLanguage] = useState("EN")
  const [price, setPrice] = useState("")
  const [quantity, setQuantity] = useState("1")
  const [description, setDescription] = useState("")
  const [shippingMethod, setShippingMethod] = useState<ShippingMethod>("standard")
  const [imageFile, setImageFile] = useState<File | null>(null)
  const [imagePreview, setImagePreview] = useState<string | null>(null)

  const [games, setGames] = useState<GameOption[]>([])
  const [sets, setSets] = useState<SetOption[]>([])
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [successResult, setSuccessResult] = useState<CreateListingResult | null>(null)
  const [marketPrice, setMarketPrice] = useState<number | null>(null)

  useEffect(() => {
    loadGames()
  }, [])

  useEffect(() => {
    if (gameCode) {
      loadSets(gameCode)
    } else {
      setSets([])
    }
  }, [gameCode])

  useEffect(() => {
    if (prefillSku) {
      fetchSkuData(prefillSku)
    }
  }, [prefillSku])

  const loadGames = async () => {
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/games`
      )
      if (response.ok) {
        const data = await response.json()
        setGames(
          (data.games || data).map((g: { code: string; name: string }) => ({
            code: g.code,
            name: g.name,
          }))
        )
      }
    } catch {
      console.error("Failed to load games")
    }
  }

  const loadSets = async (game: string) => {
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/sets?game=${game}`
      )
      if (response.ok) {
        const data = await response.json()
        setSets(
          (data.sets || data).map((s: { code: string; name: string }) => ({
            code: s.code,
            name: s.name,
          }))
        )
      }
    } catch {
      console.error("Failed to load sets")
    }
  }

  const fetchSkuData = async (sku: string) => {
    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/sku/${sku}`
      )
      if (response.ok) {
        const data = await response.json()
        setCardName(data.cardName || "")
        setGameCode(data.gameCode || "")
        setSetCode(data.setCode || "")
        setCollectorNumber(data.collectorNumber || "")
        if (data.marketPrice) {
          setMarketPrice(data.marketPrice)
          setPrice(data.marketPrice.toString())
        }
      }
    } catch {
      console.error("Failed to fetch SKU data")
    }
  }

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      setImageFile(file)
      const reader = new FileReader()
      reader.onload = (ev) => {
        setImagePreview(ev.target?.result as string)
      }
      reader.readAsDataURL(file)
    }
  }

  const buildCatalogSku = () => {
    if (gameCode && setCode && collectorNumber) {
      return `${gameCode}-${setCode}-${collectorNumber}-${language}-${condition}-NORMAL`
    }
    return prefillSku || ""
  }

  const handleSubmit = async (e: React.FormEvent, isDraft = false) => {
    e.preventDefault()
    setError(null)

    if (!cardName || !gameCode || !price) {
      setError("Please fill in all required fields")
      return
    }

    const catalogSku = buildCatalogSku()
    if (!catalogSku) {
      setError("Please fill in set and collector number to generate a valid catalog SKU")
      return
    }

    const priceInCents = Math.round(parseFloat(price) * 100)
    if (isNaN(priceInCents) || priceInCents <= 0) {
      setError("Please enter a valid price")
      return
    }

    const qty = parseInt(quantity) || 1
    if (qty < 1 || qty > 10) {
      setError("Quantity must be between 1 and 10")
      return
    }

    setLoading(true)
    try {
      let imageUrls: string[] | undefined
      if (imageFile) {
        const uploadedUrl = await uploadListingImage(imageFile)
        if (uploadedUrl) {
          imageUrls = [uploadedUrl]
        } else {
          setError("Failed to upload image. Please try again.")
          return
        }
      }

      const input = {
        catalog_sku: catalogSku,
        condition,
        language,
        price: priceInCents,
        quantity: qty,
        title: `${cardName} (${condition})`,
        description: description || undefined,
        images: imageUrls,
        shipping_method: shippingMethod,
      }

      const result = isDraft ? await saveListingDraft(input) : await createSellerListing(input)

      if (result) {
        setSuccessResult(result)
      } else {
        setError("Failed to create listing. Please try again.")
      }
    } catch {
      setError("An unexpected error occurred. Please try again.")
    } finally {
      setLoading(false)
    }
  }

  if (successResult) {
    return (
      <div className="bg-card rounded-lg border border-border p-6 max-w-md mx-auto">
        <ListingSuccessScreen
          title={successResult.title}
          price={successResult.price}
          condition={successResult.condition}
          status={successResult.status}
          onViewListing={() => router.push("/seller/dashboard/listings")}
          onListAnother={() => {
            setSuccessResult(null)
            setCardName("")
            setPrice("")
            setDescription("")
            setImageFile(null)
            setImagePreview(null)
          }}
          onClose={() => router.push("/sell")}
        />
      </div>
    )
  }

  return (
    <div className="bg-card rounded-lg border border-border p-6">
      <form onSubmit={(e) => handleSubmit(e, false)} className="space-y-6">
        {error && (
          <div className="p-3 border border-border rounded-lg" style={{ background: "rgba(239,68,68,0.08)" }}>
            <p className="text-sm" style={{ color: "var(--negative)" }}>{error}</p>
          </div>
        )}

        {/* Card Information Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Card Information</h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-primary mb-2">
                Card Name <span className="text-negative">*</span>
              </label>
              <input
                type="text"
                value={cardName}
                onChange={(e) => setCardName(e.target.value)}
                placeholder="e.g. Lightning Bolt"
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
                required
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-2">
                Game <span className="text-negative">*</span>
              </label>
              <select
                value={gameCode}
                onChange={(e) => setGameCode(e.target.value)}
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
                required
              >
                <option value="">Select a game</option>
                {games.map((game) => (
                  <option key={game.code} value={game.code}>
                    {game.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-2">Set</label>
              <select
                value={setCode}
                onChange={(e) => setSetCode(e.target.value)}
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
                disabled={!gameCode}
              >
                <option value="">Select a set</option>
                {sets.map((set) => (
                  <option key={set.code} value={set.code}>
                    {set.name}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-2">
                Collector Number
              </label>
              <input
                type="text"
                value={collectorNumber}
                onChange={(e) => setCollectorNumber(e.target.value)}
                placeholder="e.g. 001"
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-2">Language</label>
              <select
                value={language}
                onChange={(e) => setLanguage(e.target.value)}
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
              >
                {LANGUAGES.map((lang) => (
                  <option key={lang.value} value={lang.value}>
                    {lang.label}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Condition Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Condition</h2>
          <ConditionGuide value={condition} onChange={setCondition} />
        </div>

        {/* Pricing Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Pricing &amp; Quantity</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-primary mb-2">
                Price (USD) <span className="text-negative">*</span>
              </label>
              <div className="relative">
                <span className="absolute left-3 top-1/2 -translate-y-1/2 text-secondary">$</span>
                <input
                  type="number"
                  step="0.01"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                  placeholder="0.00"
                  className="w-full pl-8 pr-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
                  required
                />
              </div>
              {marketPrice && (
                <button
                  type="button"
                  onClick={() => setPrice(marketPrice.toString())}
                  className="text-xs text-action hover:underline mt-1"
                >
                  Use market price ($
                  {marketPrice.toFixed(2)})
                </button>
              )}
            </div>

            <div>
              <label className="block text-sm font-medium text-primary mb-2">
                Quantity (max 10)
              </label>
              <input
                type="number"
                min="1"
                max="10"
                value={quantity}
                onChange={(e) => setQuantity(e.target.value)}
                className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action"
              />
            </div>
          </div>
        </div>

        {/* Image Upload Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Card Image</h2>
          <div
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center justify-center w-full h-64 border-2 border-border border-dashed rounded-lg cursor-pointer bg-component hover:bg-component-hover"
          >
            {imagePreview ? (
              <div className="relative w-full h-full">
                <img
                  src={imagePreview}
                  alt="Card preview"
                  className="w-full h-full object-contain rounded-lg"
                />
                <div className="absolute inset-0 bg-black bg-opacity-50 opacity-0 hover:opacity-100 transition-opacity rounded-lg flex items-center justify-center">
                  <p className="text-white font-medium">Click to change</p>
                </div>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center pt-5 pb-6">
                <svg
                  className="w-8 h-8 mb-4 text-secondary"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z"
                  />
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M15 13a3 3 0 11-6 0 3 3 0 016 0z"
                  />
                </svg>
                <p className="mb-2 text-sm text-secondary">
                  <span className="font-semibold">Tap to take a photo</span> or upload
                </p>
                <p className="text-xs text-secondary">PNG, JPG, or WEBP (MAX. 10MB)</p>
              </div>
            )}
          </div>
          <input
            ref={fileInputRef}
            type="file"
            accept="image/*"
            capture="environment"
            onChange={handleImageChange}
            className="hidden"
          />
        </div>

        {/* Shipping Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Shipping</h2>
          <div className="space-y-2">
            {SHIPPING_OPTIONS.map((option) => (
              <label
                key={option.value}
                className={cn(
                  "flex items-center justify-between p-3 border rounded-lg cursor-pointer transition-colors",
                  shippingMethod === option.value
                    ? "border-action bg-action/5"
                    : "border-border hover:border-border-hover"
                )}
              >
                <div className="flex items-center gap-3">
                  <input
                    type="radio"
                    name="shipping"
                    value={option.value}
                    checked={shippingMethod === option.value}
                    onChange={(e) => setShippingMethod(e.target.value as ShippingMethod)}
                    className="w-4 h-4 text-action"
                  />
                  <div>
                    <div className="font-medium text-primary text-sm">{option.label}</div>
                    <div className="text-xs text-secondary">{option.description}</div>
                  </div>
                </div>
                <span className="text-sm font-medium text-primary">{option.price}</span>
              </label>
            ))}
          </div>
        </div>

        {/* Description Section */}
        <div>
          <h2 className="text-lg font-semibold text-primary mb-4">Additional Information</h2>
          <div>
            <label className="block text-sm font-medium text-primary mb-2">
              Description (Optional)
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Add any additional details about the card's condition, history, or special notes..."
              rows={4}
              maxLength={2000}
              className="w-full px-3 py-2 border border-border rounded-md bg-background text-primary focus:outline-none focus:ring-2 focus:ring-action resize-none"
            />
          </div>
        </div>

        {/* Submit Section */}
        <div className="pt-6 border-t border-border">
          <div className="flex flex-col sm:flex-row gap-4 sm:justify-end">
            <button
              type="button"
              onClick={() => router.back()}
              className="px-6 py-3 border border-border rounded-md text-primary hover:bg-component-hover transition-colors"
              disabled={loading}
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={(e) => handleSubmit(e as unknown as React.FormEvent, true)}
              disabled={loading}
              className="px-6 py-3 border border-action text-action rounded-md hover:bg-action/5 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
            >
              Save Draft
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-3 bg-action text-white rounded-md hover:bg-action-hover transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
            >
              {loading ? (
                <>
                  <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                    <circle
                      className="opacity-25"
                      cx="12"
                      cy="12"
                      r="10"
                      stroke="currentColor"
                      strokeWidth="4"
                    />
                    <path
                      className="opacity-75"
                      fill="currentColor"
                      d="m4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                    />
                  </svg>
                  Publishing...
                </>
              ) : (
                "Publish Listing"
              )}
            </button>
          </div>
        </div>
      </form>
    </div>
  )
}

import { redirect } from 'next/navigation'
import { Metadata } from 'next'
import { retrieveCustomer } from '@/lib/data/customer'
import { CardListingForm } from '@/components/seller/CardListingForm'

export const metadata: Metadata = {
  title: 'List a Card | SideDecked',
  description: 'List your trading card for sale on the SideDecked marketplace.',
}

export default async function ListCardPage() {
  const customer = await retrieveCustomer()
  
  if (!customer) {
    redirect('/user')
  }

  return (
    <main className="min-h-screen bg-background">
      <div className="container mx-auto px-4 py-8">
        <div className="max-w-2xl mx-auto">
          <div className="mb-8">
            <h1 className="text-2xl font-bold text-primary mb-2">List a Card</h1>
            <p className="text-secondary">
              Create a new listing for your trading card. Make sure to provide accurate information to attract buyers.
            </p>
          </div>
          
          <CardListingForm />
        </div>
      </div>
    </main>
  )
}

"use client"

import { cn } from "@/lib/utils"

export type ConditionCode = "NM" | "LP" | "MP" | "HP" | "DMG"

interface ConditionOption {
  code: ConditionCode
  label: string
  description: string
  examples: string
  borderColor: string
  bgColor: string
  ringColor: string
}

const CONDITIONS: ConditionOption[] = [
  {
    code: "NM",
    label: "Near Mint",
    description: "Card shows minimal to no wear. Corners are sharp, surface is clean.",
    examples: "Fresh from pack, sleeved immediately",
    borderColor: "rgba(16,185,129,0.3)",
    bgColor: "rgba(16,185,129,0.08)",
    ringColor: "rgba(16,185,129,0.6)",
  },
  {
    code: "LP",
    label: "Lightly Played",
    description: "Slight wear on edges or corners. Minor surface scratches visible at angle.",
    examples: "Played in sleeves, minor shuffling wear",
    borderColor: "rgba(132,204,22,0.3)",
    bgColor: "rgba(132,204,22,0.08)",
    ringColor: "rgba(132,204,22,0.6)",
  },
  {
    code: "MP",
    label: "Moderately Played",
    description: "Noticeable wear on edges and corners. Surface scratches visible. Still tournament legal.",
    examples: "Played unsleeved, visible edge whitening",
    borderColor: "rgba(245,158,11,0.3)",
    bgColor: "rgba(245,158,11,0.08)",
    ringColor: "rgba(245,158,11,0.6)",
  },
  {
    code: "HP",
    label: "Heavily Played",
    description: "Heavy wear throughout. May have creases, bends, or significant whitening.",
    examples: "Heavily used, noticeable creasing",
    borderColor: "rgba(249,115,22,0.3)",
    bgColor: "rgba(249,115,22,0.08)",
    ringColor: "rgba(249,115,22,0.6)",
  },
  {
    code: "DMG",
    label: "Damaged",
    description: "Major damage present. Water damage, tears, heavy creases, or writing on card.",
    examples: "Water damage, torn, written on",
    borderColor: "rgba(239,68,68,0.3)",
    bgColor: "rgba(239,68,68,0.08)",
    ringColor: "rgba(239,68,68,0.6)",
  },
]

interface ConditionGuideProps {
  value: ConditionCode
  onChange: (condition: ConditionCode) => void
  compact?: boolean
}

export function ConditionGuide({ value, onChange, compact = false }: ConditionGuideProps) {
  if (compact) {
    return (
      <div className="flex gap-2" role="radiogroup" aria-label="Card condition">
        {CONDITIONS.map((condition) => {
          const selected = value === condition.code
          return (
            <button
              key={condition.code}
              type="button"
              role="radio"
              aria-checked={selected}
              onClick={() => onChange(condition.code)}
              className={cn(
                "px-3 py-1.5 text-sm font-medium rounded-md border transition-all",
                !selected && "opacity-60 hover:opacity-100"
              )}
              style={{
                borderColor: condition.borderColor,
                background: condition.bgColor,
                ...(selected ? { boxShadow: `0 0 0 2px ${condition.ringColor}` } : {}),
              }}
            >
              {condition.code}
            </button>
          )
        })}
      </div>
    )
  }

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Card condition">
      {CONDITIONS.map((condition) => {
        const selected = value === condition.code
        return (
          <button
            key={condition.code}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => onChange(condition.code)}
            className={cn(
              "w-full text-left p-3 rounded-lg border transition-all",
              !selected && "opacity-70 hover:opacity-100"
            )}
            style={{
              borderColor: condition.borderColor,
              background: condition.bgColor,
              ...(selected ? { boxShadow: `0 0 0 2px ${condition.ringColor}` } : {}),
            }}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span className="font-semibold text-sm">{condition.code}</span>
                <span className="text-sm text-primary">{condition.label}</span>
              </div>
              {selected && (
                <svg className="w-5 h-5 text-current" fill="currentColor" viewBox="0 0 20 20">
                  <path
                    fillRule="evenodd"
                    d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                    clipRule="evenodd"
                  />
                </svg>
              )}
            </div>
            <p className="text-xs text-secondary mt-1">{condition.description}</p>
            <p className="text-xs text-tertiary mt-0.5 italic">{condition.examples}</p>
          </button>
        )
      })}
    </div>
  )
}

