"use client"

const STEPS = [
  { number: 1, label: "Identify", shortLabel: "Identify" },
  { number: 2, label: "Condition + Photos", shortLabel: "Condition" },
  { number: 3, label: "Price + Confirm", shortLabel: "Price" },
] as const

interface WizardProgressProps {
  currentStep: 1 | 2 | 3
  completedSteps: number[]
}

export function WizardProgress({ currentStep, completedSteps }: WizardProgressProps) {
  return (
    <div
      data-testid="wizard-progress"
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        marginBottom: 40,
        position: "relative",
      }}
    >
      {STEPS.map((step, i) => {
        const isActive = step.number === currentStep
        const isDone = completedSteps.includes(step.number)

        return (
          <div key={step.number} style={{ display: "contents" }}>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 8,
                position: "relative",
                zIndex: 2,
                flex: 1,
              }}
            >
              {/* Dot */}
              <div
                data-testid={`wizard-step-dot-${step.number}`}
                style={{
                  width: 36,
                  height: 36,
                  borderRadius: 999,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                  fontWeight: 700,
                  fontSize: 14,
                  transition: "all 0.2s",
                  ...(isActive
                    ? {
                        background: "var(--brand-primary)",
                        color: "white",
                        boxShadow: "0 0 20px rgba(139,92,246,0.35)",
                      }
                    : isDone
                    ? {
                        background: "var(--positive)",
                        color: "white",
                      }
                    : {
                        background: "var(--bg-surface-3)",
                        color: "var(--text-tertiary)",
                        border: "1px solid var(--border-default)",
                      }),
                }}
              >
                {isDone ? "✓" : step.number}
              </div>

              {/* Label — full on desktop, abbreviated on mobile via CSS */}
              <span
                className="wizard-step-label-full"
                style={{
                  fontSize: 12,
                  fontWeight: 600,
                  fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                  color: isActive ? "var(--brand-primary)" : "var(--text-tertiary)",
                }}
              >
                {step.label}
              </span>
              <span
                className="wizard-step-label-short"
                style={{
                  fontSize: 12,
                  fontWeight: 600,
                  fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
                  color: isActive ? "var(--brand-primary)" : "var(--text-tertiary)",
                  display: "none",
                }}
              >
                {step.shortLabel}
              </span>
            </div>

            {/* Connector between steps */}
            {i < STEPS.length - 1 && (
              <div
                data-testid={`wizard-connector-${step.number}`}
                className="wizard-step-connector-bar"
                style={{
                  height: 2,
                  marginBottom: 28,
                  background: isDone ? "var(--positive)" : "var(--bg-surface-3)",
                }}
              />
            )}
          </div>
        )
      })}

      {/* Responsive CSS for connectors and labels */}
      <style>{`
        .wizard-step-connector-bar {
          flex: 0 0 80px;
        }
        @media (max-width: 640px) {
          .wizard-step-connector-bar {
            flex: 0 0 40px !important;
          }
          .wizard-step-label-full {
            display: none !important;
          }
          .wizard-step-label-short {
            display: block !important;
          }
        }
      `}</style>
    </div>
  )
}

"use client"

import { useState, useEffect, useRef, useCallback } from "react"

export interface CardSearchResult {
  id: string
  name: string
  setName: string
  rarity: string
  imageUrl?: string
  prints: PrintOption[]
}

export interface PrintOption {
  id: string
  setName: string
  setCode: string
  collectorNumber: string
  imageUrl?: string
}

interface CardSearchInputProps {
  onCardSelect: (card: CardSearchResult) => void
  selectedCard: CardSearchResult | null
}

export function CardSearchInput({ onCardSelect, selectedCard }: CardSearchInputProps) {
  const [query, setQuery] = useState("")
  const [results, setResults] = useState<CardSearchResult[]>([])
  const [isOpen, setIsOpen] = useState(false)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const containerRef = useRef<HTMLDivElement>(null)
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const fetchResults = useCallback(async (searchQuery: string) => {
    if (searchQuery.length < 2) {
      setResults([])
      setIsOpen(false)
      return
    }

    setLoading(true)
    setError(null)

    try {
      const response = await fetch(
        `${process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL}/api/catalog/cards/search?q=${encodeURIComponent(searchQuery)}`
      )

      if (!response.ok) {
        throw new Error(`Search failed (${response.status})`)
      }

      const data = await response.json()
      const cards: CardSearchResult[] = (data.cards || data || []).map(
        (card: Record<string, unknown>) => ({
          id: card.id || card.catalogId || "",
          name: card.name || card.cardName || "",
          setName: card.setName || card.set_name || "",
          rarity: card.rarity || "",
          imageUrl: card.imageUrl || card.image_url || card.thumbnail || undefined,
          prints: (card.prints || card.printings || []).map(
            (p: Record<string, unknown>) => ({
              id: p.id || "",
              setName: p.setName || p.set_name || "",
              setCode: p.setCode || p.set_code || "",
              collectorNumber: p.collectorNumber || p.collector_number || "",
              imageUrl: p.imageUrl || p.image_url || undefined,
            })
          ),
        })
      )

      setResults(cards)
      setIsOpen(cards.length > 0)
    } catch (err) {
      const message = err instanceof Error ? err.message : "Search failed"
      console.error("[listing-wizard] Card search failed:", message)
      setError(message)
      setResults([])
      setIsOpen(false)
    } finally {
      setLoading(false)
    }
  }, [])

  const handleInputChange = (value: string) => {
    setQuery(value)

    if (debounceRef.current) {
      clearTimeout(debounceRef.current)
    }

    debounceRef.current = setTimeout(() => {
      fetchResults(value)
    }, 300)
  }

  // Close dropdown on outside click
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false)
      }
    }
    document.addEventListener("mousedown", handleClickOutside)
    return () => document.removeEventListener("mousedown", handleClickOutside)
  }, [])

  // Cleanup debounce on unmount
  useEffect(() => {
    return () => {
      if (debounceRef.current) clearTimeout(debounceRef.current)
    }
  }, [])

  const handleSelect = (card: CardSearchResult) => {
    setQuery(card.name)
    setIsOpen(false)
    onCardSelect(card)
  }

  return (
    <div ref={containerRef} style={{ position: "relative" }} data-testid="card-search-input">
      <label
        style={{
          display: "block",
          fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
          fontSize: 13,
          fontWeight: 600,
          color: "var(--text-secondary)",
          marginBottom: 8,
        }}
      >
        Card Name
      </label>
      <input
        type="text"
        value={selectedCard ? selectedCard.name : query}
        onChange={(e) => {
          if (selectedCard) {
            // If user types again after selecting, reset selection behavior
            // The parent should handle the deselect
          }
          handleInputChange(e.target.value)
        }}
        placeholder="Search by card name..."
        data-testid="card-search-field"
        style={{
          width: "100%",
          padding: "12px 16px",
          background: "var(--bg-surface-2)",
          border: "1px solid var(--border-default)",
          borderRadius: 10,
          color: "var(--text-primary)",
          fontFamily: "var(--font-body, 'Inter', sans-serif)",
          fontSize: 14,
          outline: "none",
        }}
        onFocus={() => {
          if (results.length > 0 && !selectedCard) setIsOpen(true)
        }}
      />

      {/* Loading indicator */}
      {loading && (
        <div
          style={{
            marginTop: 8,
            fontSize: 13,
            color: "var(--text-tertiary)",
          }}
        >
          Searching...
        </div>
      )}

      {/* Error state */}
      {error && (
        <div
          data-testid="card-search-error"
          style={{
            marginTop: 8,
            fontSize: 13,
            color: "var(--negative)",
            padding: "8px 12px",
            background: "rgba(239,68,68,0.08)",
            border: "1px solid rgba(239,68,68,0.2)",
            borderRadius: 8,
          }}
        >
          {error}
        </div>
      )}

      {/* Search results dropdown */}
      {isOpen && results.length > 0 && (
        <div
          data-testid="card-search-results"
          style={{
            background: "var(--bg-surface-2)",
            border: "1px solid var(--border-strong)",
            borderRadius: 12,
            marginTop: 8,
            overflow: "hidden",
            position: "absolute",
            width: "100%",
            zIndex: 50,
          }}
        >
          {results.map((card) => (
            <div
              key={card.id}
              onClick={() => handleSelect(card)}
              data-testid="card-search-result-item"
              style={{
                display: "flex",
                alignItems: "center",
                gap: 12,
                padding: "12px 16px",
                borderBottom: "1px solid var(--border-default)",
                cursor: "pointer",
                transition: "background 0.1s",
              }}
              onMouseEnter={(e) => {
                ;(e.currentTarget as HTMLDivElement).style.background = "var(--bg-surface-3)"
              }}
              onMouseLeave={(e) => {
                ;(e.currentTarget as HTMLDivElement).style.background = "transparent"
              }}
            >
              {/* Thumbnail */}
              <div
                style={{
                  width: 36,
                  height: 50,
                  background: card.imageUrl ? `url(${card.imageUrl}) center/cover` : "var(--bg-surface-3)",
                  borderRadius: 4,
                  border: "1px solid var(--border-default)",
                  flexShrink: 0,
                }}
              />
              <div style={{ flex: 1 }}>
                <div
                  style={{
                    fontSize: 14,
                    fontWeight: 500,
                    color: "var(--text-primary)",
                  }}
                >
                  {card.name}
                </div>
                <div
                  style={{
                    fontSize: 12,
                    color: "var(--text-tertiary)",
                  }}
                >
                  {card.setName}
                  {card.rarity ? ` — ${card.rarity}` : ""}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Empty state after search completes */}
      {isOpen && results.length === 0 && !loading && query.length >= 2 && !error && (
        <div
          data-testid="card-search-empty"
          style={{
            marginTop: 8,
            padding: "16px",
            background: "var(--bg-surface-2)",
            border: "1px solid var(--border-default)",
            borderRadius: 12,
            fontSize: 13,
            color: "var(--text-tertiary)",
            textAlign: "center",
          }}
        >
          No cards found
        </div>
      )}
    </div>
  )
}

"use client"

import type { PrintOption } from "./CardSearchInput"

interface PrintingGridProps {
  prints: PrintOption[]
  selectedPrint: PrintOption | null
  onSelect: (print: PrintOption) => void
}

export function PrintingGrid({ prints, selectedPrint, onSelect }: PrintingGridProps) {
  if (prints.length === 0) return null

  return (
    <div style={{ marginTop: 24 }} data-testid="printing-grid">
      <label
        style={{
          display: "block",
          fontFamily: "var(--font-heading, 'Barlow', sans-serif)",
          fontSize: 13,
          fontWeight: 600,
          color: "var(--text-secondary)",
          marginBottom: 8,
        }}
      >
        Select Printing
      </label>
      <div
        className="printing-grid-container"
        style={{
          display: "grid",
          gap: 10,
        }}
      >
        {prints.map((print) => {
          const isSelected = selectedPrint?.id === print.id

          return (
            <div
              key={print.id}
              onClick={() => onSelect(print)}
              data-testid="printing-option"
              style={{
                display: "flex",
                alignItems: "center",
                gap: 10,
                padding: "12px 16px",
                background: isSelected ? "rgba(139,92,246,0.06)" : "var(--bg-surface-2)",
                border: `1px solid ${isSelected ? "var(--brand-primary)" : "var(--border-default)"}`,
                borderRadius: 10,
                cursor: "pointer",
                transition: "all 0.15s",
              }}
              onMouseEnter={(e) => {
                if (!isSelected) {
                  ;(e.currentTarget as HTMLDivElement).style.borderColor = "var(--border-strong)"
                }
              }}
              onMouseLeave={(e) => {
                if (!isSelected) {
                  ;(e.currentTarget as HTMLDivElement).style.borderColor = "var(--border-default)"
                }
              }}
            >
              {/* Set icon placeholder */}
              <div
                style={{
                  width: 28,
                  height: 28,
                  background: "var(--bg-surface-3)",
                  borderRadius: 6,
                  flexShrink: 0,
                }}
              />
              <div>
                <div
                  style={{
                    fontSize: 13,
                    fontWeight: 500,
                    color: "var(--text-primary)",
                  }}
                >
                  {print.setName}
                </div>
                <div
                  style={{
                    fontSize: 11,
                    color: "var(--text-tertiary)",
                    fontFamily: "var(--font-mono, 'DM Mono', monospace)",
                  }}
                >
                  {print.setCode} #{print.collectorNumber}
                </div>
              </div>
            </div>
          )
        })}
      </div>

      <style>{`
        .printing-grid-container {
          grid-template-columns: repeat(2, 1fr);
        }
        @media (max-width: 640px) {
          .printing-grid-container {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  )
}

