import { render, screen, fireEvent, waitFor, act } from "@testing-library/react"
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest"
import { ListingWizard } from "../wizard/ListingWizard"
import { WizardProgress } from "../wizard/WizardProgress"
import { CardSearchInput } from "../wizard/CardSearchInput"
import { PrintingGrid } from "../wizard/PrintingGrid"
import { WizardStepIdentify } from "../wizard/WizardStepIdentify"
import type { CardSearchResult, PrintOption } from "../wizard/CardSearchInput"

// --- Mocks ---

const mockCard: CardSearchResult = {
  id: "card-1",
  name: "Ragavan, Nimble Pilferer",
  setName: "Modern Horizons 2",
  rarity: "Mythic Rare",
  prints: [
    {
      id: "print-1",
      setName: "Modern Horizons 2",
      setCode: "MH2",
      collectorNumber: "138",
    },
    {
      id: "print-2",
      setName: "MH2 (Extended Art)",
      setCode: "MH2",
      collectorNumber: "382",
    },
  ],
}

const mockPrint: PrintOption = mockCard.prints[0]

function mockFetchSuccess(data: unknown) {
  return vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve(data),
  })
}

function mockFetchError(status = 500) {
  return vi.fn().mockResolvedValue({
    ok: false,
    status,
    json: () => Promise.resolve({ error: "Server error" }),
  })
}

// --- WizardProgress ---

describe("WizardProgress", () => {
  it("renders 3 step indicators", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    expect(screen.getByTestId("wizard-progress")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-1")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-2")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-dot-3")).toBeInTheDocument()
  })

  it("shows step 1 as active with brand-primary background", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("1")
    expect(dot1.style.background).toBe("var(--brand-primary)")
  })

  it("shows completed step with checkmark and positive background", () => {
    render(<WizardProgress currentStep={2} completedSteps={[1]} />)

    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("✓")
    expect(dot1.style.background).toBe("var(--positive)")
  })

  it("shows pending step with surface-3 background", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    const dot3 = screen.getByTestId("wizard-step-dot-3")
    expect(dot3.textContent).toBe("3")
    expect(dot3.style.background).toBe("var(--bg-surface-3)")
  })

  it("renders connectors between steps", () => {
    render(<WizardProgress currentStep={2} completedSteps={[1]} />)

    const connector1 = screen.getByTestId("wizard-connector-1")
    expect(connector1).toBeInTheDocument()
    // Completed connector should use positive color
    expect(connector1.style.background).toBe("var(--positive)")
  })

  it("shows step labels", () => {
    render(<WizardProgress currentStep={1} completedSteps={[]} />)

    expect(screen.getByText("Identify")).toBeInTheDocument()
    expect(screen.getByText("Condition + Photos")).toBeInTheDocument()
    expect(screen.getByText("Price + Confirm")).toBeInTheDocument()
  })
})

// --- CardSearchInput ---

describe("CardSearchInput", () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
    vi.restoreAllMocks()
  })

  it("renders search input", () => {
    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    expect(screen.getByTestId("card-search-field")).toBeInTheDocument()
    expect(screen.getByPlaceholderText("Search by card name...")).toBeInTheDocument()
  })

  it("debounces search at 300ms", async () => {
    const fetchMock = mockFetchSuccess({ cards: [mockCard] })
    global.fetch = fetchMock

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "Ragavan" } })

    // Not called yet
    expect(fetchMock).not.toHaveBeenCalled()

    // Advance past debounce
    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    expect(fetchMock).toHaveBeenCalledTimes(1)
    expect(fetchMock).toHaveBeenCalledWith(
      expect.stringContaining("/api/catalog/cards/search?q=Ragavan")
    )
  })

  it("renders search results", async () => {
    global.fetch = mockFetchSuccess({ cards: [mockCard] })

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "Ragavan" } })

    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    expect(screen.getByText("Ragavan, Nimble Pilferer")).toBeInTheDocument()
    expect(screen.getByText("Modern Horizons 2 — Mythic Rare")).toBeInTheDocument()
  })

  it("calls onCardSelect when a result is clicked", async () => {
    global.fetch = mockFetchSuccess({ cards: [mockCard] })
    const onCardSelect = vi.fn()

    render(<CardSearchInput onCardSelect={onCardSelect} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "Ragavan" } })

    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    const resultItem = screen.getByTestId("card-search-result-item")
    fireEvent.click(resultItem)

    expect(onCardSelect).toHaveBeenCalledWith(mockCard)
  })

  it("shows error state on API failure", async () => {
    global.fetch = mockFetchError(500)

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "Ragavan" } })

    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-error")).toBeInTheDocument()
    })
  })

  it("does not search for queries shorter than 2 characters", async () => {
    const fetchMock = mockFetchSuccess({ cards: [] })
    global.fetch = fetchMock

    render(<CardSearchInput onCardSelect={vi.fn()} selectedCard={null} />)

    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "R" } })

    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    expect(fetchMock).not.toHaveBeenCalled()
  })
})

// --- PrintingGrid ---

describe("PrintingGrid", () => {
  it("renders nothing when prints array is empty", () => {
    const { container } = render(
      <PrintingGrid prints={[]} selectedPrint={null} onSelect={vi.fn()} />
    )
    expect(container.innerHTML).toBe("")
  })

  it("renders printing options", () => {
    render(
      <PrintingGrid prints={mockCard.prints} selectedPrint={null} onSelect={vi.fn()} />
    )

    expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
    expect(screen.getAllByTestId("printing-option")).toHaveLength(2)
    expect(screen.getByText("Modern Horizons 2")).toBeInTheDocument()
    expect(screen.getByText("MH2 #138")).toBeInTheDocument()
  })

  it("shows selected state with brand-primary border", () => {
    render(
      <PrintingGrid prints={mockCard.prints} selectedPrint={mockPrint} onSelect={vi.fn()} />
    )

    const options = screen.getAllByTestId("printing-option")
    expect(options[0].style.borderColor).toContain("var(--brand-primary)")
    expect(options[1].style.borderColor).toContain("var(--border-default)")
  })

  it("calls onSelect when option clicked", () => {
    const onSelect = vi.fn()
    render(
      <PrintingGrid prints={mockCard.prints} selectedPrint={null} onSelect={onSelect} />
    )

    const options = screen.getAllByTestId("printing-option")
    fireEvent.click(options[1])

    expect(onSelect).toHaveBeenCalledWith(mockCard.prints[1])
  })
})

// --- WizardStepIdentify ---

describe("WizardStepIdentify", () => {
  it("renders Find Your Card title", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    expect(screen.getByText("Find Your Card")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-identify")).toBeInTheDocument()
  })

  it("disables Continue when no print selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    const btn = screen.getByTestId("wizard-continue-btn")
    expect(btn).toBeDisabled()
  })

  it("enables Continue when card and print are selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={mockPrint}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    const btn = screen.getByTestId("wizard-continue-btn")
    expect(btn).not.toBeDisabled()
  })

  it("calls onContinue when Continue is clicked", () => {
    const onContinue = vi.fn()

    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={mockPrint}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={onContinue}
      />
    )

    fireEvent.click(screen.getByTestId("wizard-continue-btn"))
    expect(onContinue).toHaveBeenCalledTimes(1)
  })

  it("shows printing grid when card is selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={mockCard}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
  })

  it("hides printing grid when no card selected", () => {
    render(
      <WizardStepIdentify
        selectedCard={null}
        selectedPrint={null}
        onCardSelect={vi.fn()}
        onPrintSelect={vi.fn()}
        onContinue={vi.fn()}
      />
    )

    expect(screen.queryByTestId("printing-grid")).not.toBeInTheDocument()
  })
})

// --- ListingWizard (integration) ---

describe("ListingWizard", () => {
  beforeEach(() => {
    vi.restoreAllMocks()
  })

  it("renders wizard with step 1 active", () => {
    render(<ListingWizard />)

    expect(screen.getByTestId("listing-wizard")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-progress")).toBeInTheDocument()
    expect(screen.getByTestId("wizard-step-identify")).toBeInTheDocument()

    // Step 1 dot should be active
    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.style.background).toBe("var(--brand-primary)")
  })

  it("advances to step 2 when Continue clicked after selecting card and print", async () => {
    vi.useFakeTimers()
    global.fetch = mockFetchSuccess({ cards: [mockCard] })

    render(<ListingWizard />)

    // Search for a card
    const input = screen.getByTestId("card-search-field")
    fireEvent.change(input, { target: { value: "Ragavan" } })

    await act(async () => {
      vi.advanceTimersByTime(300)
    })

    await waitFor(() => {
      expect(screen.getByTestId("card-search-results")).toBeInTheDocument()
    })

    // Select a card
    fireEvent.click(screen.getByTestId("card-search-result-item"))

    await waitFor(() => {
      expect(screen.getByTestId("printing-grid")).toBeInTheDocument()
    })

    // Select a print
    const printOptions = screen.getAllByTestId("printing-option")
    fireEvent.click(printOptions[0])

    // Continue should be enabled, click it
    const continueBtn = screen.getByTestId("wizard-continue-btn")
    expect(continueBtn).not.toBeDisabled()
    fireEvent.click(continueBtn)

    // Should be on step 2 now
    await waitFor(() => {
      expect(screen.getByTestId("wizard-step-condition")).toBeInTheDocument()
    })

    // Step 1 should be marked done
    const dot1 = screen.getByTestId("wizard-step-dot-1")
    expect(dot1.textContent).toBe("✓")
    expect(dot1.style.background).toBe("var(--positive)")

    vi.useRealTimers()
  })

  it("renders with prefillSku and starts at step 2", async () => {
    global.fetch = mockFetchSuccess({
      cardId: "card-1",
      cardName: "Ragavan, Nimble Pilferer",
      setName: "Modern Horizons 2",
      setCode: "MH2",
